<?php include "db.php"; $keyword=$_GET['keyword']??''; if($keyword!=''){ $k="%$keyword%"; $stmt=$conn->prepare("SELECT * FROM lesson_plans WHERE grade_level LIKE ? OR subject LIKE ? OR term LIKE ? OR topic LIKE ? OR lesson_date LIKE ? ORDER BY lesson_date DESC"); $stmt->bind_param('sssss',$k,$k,$k,$k,$k); $stmt->execute(); $result=$stmt->get_result(); } else { $result=$conn->query("SELECT * FROM lesson_plans ORDER BY lesson_date DESC"); } ?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Search</title><link rel="stylesheet" href="style.css"></head><body><div class="container"><h1>Search Lesson Plans</h1><form method="GET"><label>Search by Grade, Learning Area, Term, Name of Lesson, or Date</label><input name="keyword" value="<?php echo htmlspecialchars($keyword); ?>"><input type="submit" value="Search"><a href="index.php">Back</a></form><table><tr><th>ID</th><th>Grade</th><th>Learning Area</th><th>Term</th><th>Date</th><th>Name of Lesson</th><th>Actions</th></tr><?php while($row=$result->fetch_assoc()){ ?><tr><td><?php echo $row['id']; ?></td><td><?php echo htmlspecialchars($row['grade_level']); ?></td><td><?php echo htmlspecialchars($row['subject']); ?></td><td><?php echo htmlspecialchars($row['term']); ?></td><td><?php echo htmlspecialchars($row['lesson_date']); ?></td><td><?php echo htmlspecialchars($row['topic']); ?></td><td><a href="view.php?id=<?php echo $row['id']; ?>">View</a><a href="edit.php?id=<?php echo $row['id']; ?>">Edit</a><a href="export_word.php?id=<?php echo $row['id']; ?>">Word</a><a href="export_excel.php?id=<?php echo $row['id']; ?>">Excel</a></td></tr><?php } ?></table></div></body></html>
